import { GoogleGenAI, Type, Schema } from "@google/genai";
import { CaseSummary, CaseSearchResult, Jurisdiction } from "../types";

// --- CONFIGURATION ---
// Using Gemini 3 Flash for fast search and Gemini 3 Pro for deep legal analysis.
const SEARCH_MODEL = 'gemini-3-flash-preview'; 
const ANALYSIS_MODEL = 'gemini-3-pro-preview'; 

// --- HELPER ---
// Helper to initialize AI client safely at runtime
const getAiClient = () => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

// Helper to clean potential markdown formatting from JSON response
const cleanJson = (text: string) => {
  if (!text) return "";
  // Remove markdown code blocks if present (```json or ```)
  let clean = text.replace(/```json/g, "").replace(/```/g, "");
  return clean.trim();
};

// --- SCHEMAS ---

const caseSummarySchema: Schema = {
  type: Type.OBJECT,
  properties: {
    caseName: { type: Type.STRING, description: "Official name of the case" },
    citation: { type: Type.STRING, description: "Primary legal citation" },
    court: { type: Type.STRING, description: "Name of the court" },
    year: { type: Type.INTEGER, description: "Year of the judgment" },
    benchStrength: { type: Type.STRING, description: "Number of judges" },
    judges: { type: Type.ARRAY, items: { type: Type.STRING } },
    jurisdiction: { type: Type.STRING },
    facts: { type: Type.STRING, description: "Detailed narrative of facts." },
    timeline: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          date: { type: Type.STRING },
          event: { type: Type.STRING },
        },
      },
    },
    proceduralHistory: {
