// Helper to clean Markdown code blocks from JSON string
const cleanJson = (text: string) => {
  if (!text) return "";
  let clean = text.trim();
  // Remove markdown wrapping like ```json ... ```
  if (clean.startsWith("```")) {
    clean = clean.replace(/^```(json)?/i, "").replace(/```$/, "");
  }
  return clean.trim();
};

