export const searchCaseDatabase = async (
  query: string,
  jurisdiction: Jurisdiction
): Promise<CaseSearchResult[]> => {
  try {
    if (!apiKey) throw new Error("API Key not found");

    const prompt = `
      User Query: "${query}"
      Jurisdiction: ${jurisdiction}

      Task: Find the top 4 most relevant legal cases/precedents.
      Constraint: Provide direct PDF links where possible.
    `;

    const response = await ai.models.generateContent({
      model: SEARCH_MODEL,
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: searchResultSchema,
        temperature: 0.1, 
      }
    });

    if (!response.text) throw new Error("No response generated");

    return JSON.parse(cleanJson(response.text)) as CaseSearchResult[];
  } catch (error) {
    console.error("Search Error:", error);
    throw error;
  }
};

export const fetchCaseSummary = async (
  query: string, 
  jurisdiction: Jurisdiction,
  isVakilMode: boolean = false,
  isRawText: boolean = false
): Promise<CaseSummary> => {
  try {
    if (!apiKey) throw new Error("API Key not found");

    let prompt = "";
    const persona = isVakilMode 
      ? `Role: Senior Advocate (Street Smart). Tone: Blunt, strategic, authoritative. Focus on "What does this mean for my client?".`
      : `Role: Constitutional Scholar. Tone: Formal, detailed, objective.`;

    if (isRawText) {
      prompt = `
        ${persona}
        Analyze the raw text provided below. Extract all legal elements into the schema.
        Raw Text: """${query.substring(0, 30000)}"""
      `;
    } else {
      prompt = `
        ${persona}
        Analyze Case: "${query}" (${jurisdiction}).
        Task: Provide a deep, structured legal summary.

        Requirements:
        1. Facts: Detailed narrative (500 words).
        2. IRAC: Strict Issue, Rule, Analysis, Conclusion breakdown.
        3. Sources: Find 9 distinct URLs (Official, Legal DB, News).
      `;
    }

    const response = await ai.models.generateContent({
      model: ANALYSIS_MODEL,
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }], 
        responseMimeType: "application/json",
        responseSchema: caseSummarySchema,
        temperature: 0.2, 
      }
    });

    if (!response.text) throw new Error("No response generated");

    return JSON.parse(cleanJson(response.text)) as CaseSummary;

  } catch (error) {
    console.error("Gemini Legal Search Error:", error);
    throw error;
  }
};

