      <div className={`${theme.bgPaper} rounded-sm shadow-[0_20px_70px_rgba(0,0,0,0.5)] border-2 ${theme.border} overflow-hidden relative group transition-colors duration-500`}>

        {/* Subtle Noise Texture */}
        <div className={`absolute inset-0 bg-noise opacity-30 pointer-events-none mix-blend-multiply ${isVakilMode ? 'invert brightness-50 contrast-150' : ''}`}></div>

        {/* Top Bar */}
        <div className={`h-3 relative z-20 ${isVakilMode ? 'bg-gradient-to-r from-green-900 via-neon-green to-green-900' : 'bg-gradient-to-r from-yellow-700 via-yellow-400 to-yellow-700'}`}></div>

        {/* Header Section */}
        <div className={`px-8 py-10 border-b-2 ${theme.sectionDivider} relative z-10 bg-inherit`}>
           <div className="flex items-center gap-3 mb-3">
             <span className={`${theme.fontHead} text-sm font-black tracking-[0.2em] uppercase ${isVakilMode ? 'text-neon-green' : 'text-slate-500'}`}>
                {summary.court} • {summary.year}
             </span>
           </div>

           <h2 className={`${isVakilMode ? 'font-mono text-white tracking-tighter' : 'font-display text-black'} text-5xl md:text-7xl font-black leading-tight mb-6`}>
              {summary.caseName}
           </h2>

           <div className="flex flex-wrap items-center gap-4">
             <span className={`font-mono text-lg font-bold tracking-wide px-4 py-2 rounded-md ${isVakilMode ? 'border border-gray-600 text-white bg-gray-900' : 'border border-slate-400 bg-white text-black shadow-sm'}`}>
               {summary.citation}
             </span>
           </div>

           {/* Bench Display */}
           <div className={`mt-10 pt-8 border-t ${theme.sectionDivider}`}>
              <h4 className={`text-xs font-black uppercase tracking-[0.2em] mb-4 flex items-center gap-2 ${isVakilMode ? 'text-gray-400' : 'text-slate-500'}`}>
                Honorable Bench
              </h4>
              <div className="flex flex-wrap gap-3">
                {summary.judges?.map((judge, i) => (
                  <div key={i} className={`flex items-center gap-2 px-4 py-2 border-2 rounded shadow-sm ${isVakilMode ? 'bg-gray-900 border-gray-600 text-white' : 'bg-white border-slate-300 text-slate-900'}`}>
                    <span className={`text-sm font-bold uppercase ${theme.fontHead}`}>{judge}</span>
                  </div>
                ))}
              </div>
           </div>
        </div>

        {/* Main Content Body */}
        <div className={`p-8 md:p-14 relative z-10 ${theme.textBody}`}>

            {/* Vakil's Take */}
            {isVakilMode && summary.vakilTake && (
              <div className="mb-14 p-8 bg-black border-2 border-neon-green shadow-[0_0_20px_rgba(57,255,20,0.2)]">
                <h3 className="font-mono text-neon-green font-black text-xl mb-4 flex items-center gap-2 uppercase tracking-widest border-b border-gray-800 pb-2">VAKIL'S STRATEGY NOTE</h3>
                <p className="font-mono text-lg leading-loose text-white">{summary.vakilTake}</p>
              </div>
            )}

            {/* Procedural History Flowchart */}
            {summary.proceduralHistory && summary.proceduralHistory.length > 0 && (
              <div className="mb-16">
                 <h4 className={`${theme.fontHead} ${isVakilMode ? 'text-neon-green' : 'text-slate-600'} text-sm font-black uppercase tracking-[0.2em] mb-8`}>Procedural Timeline</h4>
                 <div className="flex flex-col gap-6">
                    {summary.proceduralHistory.map((step, i) => (
                      <div key={i} className="flex items-center gap-6">
                         <div className={`w-10 h-10 shrink-0 flex items-center justify-center rounded-full text-lg font-black border-2 ${isVakilMode ? 'bg-black border-neon-green text-neon-green' : 'bg-yellow-100 border-yellow-500 text-yellow-800'}`}>
                           {i + 1}
                         </div>
                         <div className={`flex-1 p-5 rounded-lg border-2 shadow-sm ${isVakilMode ? 'bg-gray-900 border-gray-700 text-white' : 'bg-white border-slate-200 text-slate-800'}`}>
                           <p className="text-xl font-bold font-serif">{step}</p>
                         </div>
                      </div>
                    ))}
                 </div>
              </div>
            )}

            {/* Facts - Large Readable Text */}
            <div className="mb-16">
              <h4 className={`${theme.fontHead} ${isVakilMode ? 'text-neon-green' : 'text-slate-600'} text-sm font-black uppercase tracking-[0.2em] mb-6 border-b border-gray-500/30 pb-3`}>Facts of the Case</h4>
              <p className={`text-justify ${theme.fontBody} ${isVakilMode ? 'text-gray-200' : 'text-[#1a1a1a]'}`}>{summary.facts}</p>
            </div>

            {/* Arguments - High Contrast Boxes */}
            {(summary.petitionerArguments || summary.respondentArguments) && (
              <div className="mb-16 grid grid-cols-1 md:grid-cols-2 gap-10">
                 <div className={`p-8 border-l-8 rounded-r-lg ${isVakilMode ? 'bg-gray-900 border-gray-500' : 'bg-slate-100 border-slate-500'}`}>
                    <h4 className="text-sm uppercase font-black tracking-widest mb-4 opacity-70">Petitioner's Stand</h4>
                    <p className={`text-lg leading-relaxed font-serif ${isVakilMode ? 'text-white' : 'text-slate-900'}`}>{summary.petitionerArguments}</p>
                 </div>
                 <div className={`p-8 border-l-8 rounded-r-lg ${isVakilMode ? 'bg-gray-900 border-neon-green' : 'bg-yellow-50 border-yellow-500'}`}>
                    <h4 className="text-sm uppercase font-black tracking-widest mb-4 opacity-70">Respondent's Stand</h4>
                    <p className={`text-lg leading-relaxed font-serif ${isVakilMode ? 'text-white' : 'text-slate-900'}`}>{summary.respondentArguments}</p>
                 </div>
              </div>
            )}

            {/* Ratio Decidendi - Centerpiece */}
            <div className={`mb-16 relative p-12 border-4 ${isVakilMode ? 'bg-black border-neon-green/50 border-dashed' : 'bg-white border-yellow-500/50 rounded-lg shadow-lg'}`}>
              <div className="absolute top-0 left-1/2 -translate-x-1/2 -translate-y-1/2 px-6 py-2 bg-black border-2 border-yellow-500 rounded-full z-10">
                <span className={`${theme.fontHead} font-black text-yellow-400 tracking-[0.2em] text-xs`}>RATIO DECIDENDI</span>
              </div>
              <p className={`${isVakilMode ? 'font-mono text-white text-xl leading-relaxed' : 'font-display text-3xl text-black font-black italic text-center leading-relaxed'}`}>"{summary.ratioDecidendi}"</p>
            </div>

            {/* Held */}
            <div className={`p-10 mb-16 rounded-lg ${isVakilMode ? 'bg-gray-900 border-l-8 border-neon-green' : 'bg-yellow-100/50 border-l-8 border-yellow-600'}`}>
               <h4 className={`${theme.fontHead} text-lg font-black mb-4 uppercase`}>Judgment Held:</h4>
               <p className={`${theme.fontBody} font-bold`}>{summary.decision}</p>
            </div>

            {/* IRAC - Large Unified Cards */}
            {summary.irac && (
              <div className={`mb-16 ${isVakilMode ? 'bg-black border border-gray-700' : 'bg-slate-50 border-t-8 border-yellow-500 shadow-xl rounded-lg'}`}>
                <div className={`p-6 border-b ${isVakilMode ? 'border-gray-800' : 'border-slate-200 bg-slate-100'}`}>
                  <h3 className={`${theme.fontHead} text-2xl font-black tracking-widest flex items-center gap-3`}>IRAC ANALYSIS</h3>
                </div>
                <div className="p-10 space-y-10">
                  {[
                    { label: 'ISSUE', content: summary.irac.issue, num: 'I' },
                    { label: 'RULE', content: summary.irac.rule, num: 'II' },
                    { label: 'ANALYSIS', content: summary.irac.analysis, num: 'III' },
                    { label: 'CONCLUSION', content: summary.irac.conclusion, num: 'IV' }
                  ].map((item, idx) => (
                    <div key={idx} className="flex gap-6">
                       <div className={`w-12 h-12 shrink-0 rounded-full flex items-center justify-center font-black text-xl ${isVakilMode ? 'bg-gray-800 text-neon-green' : 'bg-yellow-200 text-yellow-800'}`}>{item.num}</div>
                       <div>
                         <h4 className="font-black opacity-60 mb-2 uppercase tracking-wider text-sm">{item.label}</h4>
                         <p className={`leading-relaxed text-justify ${isVakilMode ? 'font-mono text-lg text-gray-300' : 'font-serif text-xl font-medium text-slate-800'}`}>{item.content}</p>
                       </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Trajectory */}
            <div className={`border-t-4 p-10 mb-16 ${isVakilMode ? 'bg-black border-gray-800' : 'bg-slate-100 border-slate-300'}`}>
              <h3 className={`${theme.fontHead} text-center text-3xl mb-12 tracking-[0.2em] font-black uppercase text-slate-700`}>Legal Lineage</h3>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
                <div>
                  <h4 className={`text-sm font-black tracking-widest opacity-60 mb-6 pb-2 border-b-2 ${theme.sectionDivider}`}>PRECEDENTS CITED</h4>
                  <div className="space-y-4">{summary.precedents?.length > 0 ? summary.precedents.map((p, i) => <div key={i}>{renderRelatedCase(p)}</div>) : <p className="text-lg italic opacity-50">No precedents listed.</p>}</div>
                </div>
                <div>
                  <h4 className={`text-sm font-black tracking-widest opacity-60 mb-6 pb-2 border-b-2 ${theme.sectionDivider}`}>SUBSEQUENT CITATIONS</h4>
                  <div className="space-y-4">{summary.subsequentDevelopments?.length > 0 ? summary.subsequentDevelopments.map((p, i) => <div key={i}>{renderRelatedCase(p)}</div>) : <p className="text-lg italic opacity-50">No developments listed.</p>}</div>
                </div>
              </div>
            </div>

            {/* Stats & Analytics */}
            <div className={`mt-20 pt-16 border-t-2 ${theme.sectionDivider}`}>
                {summary.stats && (
                   <div className="mb-20">
                      <h3 className={`${theme.fontHead} text-center text-2xl font-black mb-16 tracking-widest opacity-80 uppercase`}>Case Analytics</h3>
                      <div className="grid grid-cols-1 md:grid-cols-3 gap-10">
                          {/* Impact */}
                          <div className={`flex flex-col items-center p-8 rounded-lg border-2 ${isVakilMode ? 'bg-black border-gray-800' : 'bg-white border-slate-200 shadow-sm'}`}>
                             <h4 className="text-xs uppercase font-black tracking-widest mb-6 opacity-60">Impact Score</h4>
                             <div className="relative w-40 h-40 rounded-full shadow-lg mb-6 flex items-center justify-center bg-gradient-to-br from-yellow-400 to-red-500">
                                <div className={`absolute inset-4 rounded-full flex items-center justify-center flex-col ${isVakilMode ? 'bg-black' : 'bg-white'}`}>
                                   <span className="font-black text-4xl font-display">{summary.stats.citationCount}</span>
                                   <span className="text-[10px] uppercase opacity-60 tracking-widest mt-1">Citations</span>
                                </div>
                             </div>
                             <div className="w-full mt-auto">
                               <div className="flex justify-between text-xs font-bold mb-2"><span>Impact Factor</span><span>{summary.stats.impactScore}/100</span></div>
                               <div className="h-4 w-full bg-slate-200 rounded-full overflow-hidden"><div className="h-full bg-yellow-500" style={{ width: `${summary.stats.impactScore}%` }}></div></div>
                             </div>
                          </div>

                          {/* Concepts Cloud */}
                          <div className={`col-span-1 md:col-span-2 p-8 rounded-lg border-2 ${isVakilMode ? 'bg-black border-gray-800' : 'bg-white border-slate-200 shadow-sm'}`}>
                             <h4 className="text-xs uppercase font-black tracking-widest mb-6 opacity-60 text-center">Core Legal Doctrines</h4>
                             <div className="flex flex-wrap justify-center gap-4 h-full content-center">
                               {summary.stats.legalConcepts?.map((concept, idx) => (
                                 <span key={idx} className={`px-6 py-3 text-lg font-bold rounded-full border-2 ${theme.conceptPill} shadow-sm transition-transform hover:scale-110`}>
                                   {concept}
                                 </span>
                               ))}
                             </div>
                          </div>
                      </div>
                   </div>
                )}

                {/* Sources - 3x3 Grid with Larger Touch Targets */}
                <div className={`p-10 rounded-lg border-2 ${isVakilMode ? 'bg-black border-gray-700' : 'bg-slate-50 border-slate-300'}`}>
                    <h3 className={`${theme.fontHead} text-center text-lg font-black mb-10 tracking-widest uppercase opacity-70`}>External Sources (Direct Links)</h3>
                    <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-6">
                        {summary.sources && summary.sources.map((source, idx) => (
                           <a 
                             key={idx} 
                             href={source.url} 
                             target="_blank" 
                             rel="noreferrer"
                             className={`flex flex-col items-center justify-center p-6 border-2 rounded transition-all hover:-translate-y-2 shadow-sm group relative overflow-hidden h-36 ${isVakilMode ? 'bg-gray-900 border-gray-700 hover:border-neon-green' : 'bg-white border-slate-300 hover:border-yellow-500'}`}
                           >
                              <span className={`text-3xl mb-3 opacity-50 ${isVakilMode ? 'text-gray-500' : 'text-slate-400'}`}>
                                {source.type.includes('OFFICIAL') ? '🏛️' : (source.type.includes('LEGAL') ? '⚖️' : '📰')}
                              </span>
                              <span className={`font-bold text-sm text-center leading-tight mb-2 line-clamp-2 ${isVakilMode ? 'text-gray-100' : 'text-slate-900'}`}>
                                {source.name}
                              </span>
                              <span className="mt-auto text-[10px] uppercase tracking-wider font-bold pt-1 text-yellow-600 group-hover:underline">
                                Click to Open ↗
                              </span>
                           </a>
                        ))}
                    </div>
                </div>

            </div>
        </div>

      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { SearchMode, Jurisdiction, HistoryItem } from '../types';

interface HeroSectionProps {
  query: string;
  setQuery: (q: string) => void;
  mode: SearchMode;
  setMode: (m: SearchMode) => void;
  jurisdiction: Jurisdiction;
  setJurisdiction: (j: Jurisdiction) => void;
  onSearch: () => void;
  isLoading: boolean;
  history: HistoryItem[];
  onHistorySelect: (item: HistoryItem) => void;
}

const MOCK_CASE_DB = [
  "Kesavananda Bharati v. State of Kerala",
  "Maneka Gandhi v. Union of India",
  "Minerva Mills Ltd. v. Union of India",
  "Golaknath v. State of Punjab",
  "Shah Bano Begum Case",
  "Vishaka v. State of Rajasthan",
  "Puttaswamy v. Union of India (Privacy Case)",
  "Indra Sawhney v. Union of India",
  "ADM Jabalpur v. Shivkant Shukla",
  "S.R. Bommai v. Union of India"
];

export const HeroSection: React.FC<HeroSectionProps> = ({
  query,
  setQuery,
  mode,
  setMode,
  jurisdiction,
  setJurisdiction,
  onSearch,
  isLoading,
  history,
  onHistorySelect
}) => {
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const wrapperRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (mode === SearchMode.CASE_NAME && query.length > 2) {
      const filtered = MOCK_CASE_DB.filter(c => 
        c.toLowerCase().includes(query.toLowerCase())
      ).slice(0, 5);
      setSuggestions(filtered);
      setShowSuggestions(filtered.length > 0);
    } else {
      setShowSuggestions(false);
    }
  }, [query, mode]);

  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (wrapperRef.current && !wrapperRef.current.contains(event.target as Node)) {
        setShowSuggestions(false);
      }
    }
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, [wrapperRef]);

  const handleSuggestionClick = (suggestion: string) => {
    setQuery(suggestion);
    setShowSuggestions(false);
  };

  return (
    <div className="relative pt-32 pb-20 px-4 overflow-hidden min-h-[70vh] flex flex-col justify-center">

      {/* Background Decorative Elements */}
      <div className="absolute top-0 left-1/2 -translate-x-1/2 w-[1200px] h-[800px] bg-navy-800/30 rounded-full blur-[150px] -z-10 pointer-events-none"></div>

      <div className="max-w-6xl mx-auto text-center relative z-10 w-full">

        {/* Logo Section */}
        <div className="mb-16 animate-fade-in-down flex flex-col items-center">

          <div className="relative w-32 h-32 mb-6 group cursor-default">
             <div className="absolute inset-0 bg-yellow-500/20 blur-3xl rounded-full opacity-0 group-hover:opacity-100 transition-opacity duration-500"></div>
             <svg viewBox="0 0 100 100" className="w-full h-full drop-shadow-2xl overflow-visible">
               <defs>
                 <linearGradient id="goldGrad" x1="0%" y1="0%" x2="100%" y2="100%">
                   <stop offset="0%" stopColor="#f59e0b" />
                   <stop offset="50%" stopColor="#fcd34d" />
                   <stop offset="100%" stopColor="#f59e0b" />
                 </linearGradient>
               </defs>
               <path d="M50 10 L85 25 V 55 Q 85 85 50 95 Q 15 85 15 55 V 25 Z" fill="none" stroke="url(#goldGrad)" strokeWidth="1" className="opacity-30" />
               <path d="M40 25 V 65 Q 40 80 25 80" fill="none" stroke="url(#goldGrad)" strokeWidth="6" strokeLinecap="square" />
               <path d="M60 25 V 80 H 80" fill="none" stroke="url(#goldGrad)" strokeWidth="6" strokeLinecap="square" />
               <line x1="50" y1="20" x2="50" y2="85" stroke="#fcd34d" strokeWidth="1" className="opacity-50" strokeDasharray="2 2" />
             </svg>
          </div>

          <div className="inline-flex items-center justify-center px-8 py-3 mb-6 border-y border-yellow-500/30 bg-navy-950/40 backdrop-blur-md">
            <span className="text-yellow-400 text-xs font-cinzel tracking-[0.4em] font-bold uppercase">
              Est. 2026 • AI Legal Research
            </span>
          </div>

          <h1 className="font-display text-7xl md:text-9xl font-bold mb-4 tracking-tighter text-white drop-shadow-2xl relative inline-block">
            Juris<span className="text-shine italic font-serif font-light animate-shine text-yellow-400">Lens</span>
          </h1>

          <div className="flex items-center justify-center gap-6 my-10 opacity-80">
            <div className="h-px w-24 bg-gradient-to-r from-transparent to-yellow-500"></div>
            <p className="text-slate-200 text-2xl font-serif italic tracking-wide">
              "Fiat Justitia Ruat Caelum"
            </p>
            <div className="h-px w-24 bg-gradient-to-l from-transparent to-yellow-500"></div>
          </div>
        </div>

        {/* Search Interface - HIGH VISIBILITY */}
        {!isLoading && (
          <div ref={wrapperRef} className="bg-navy-950/90 backdrop-blur-3xl rounded-lg shadow-[0_30px_100px_rgba(0,0,0,0.8)] border border-slate-700 p-6 max-w-5xl mx-auto transform transition-all hover:border-yellow-500/50 group relative z-50">
            <div className="flex flex-col md:flex-row gap-6">

              {/* Mode Select */}
              <div className="relative min-w-[220px] bg-navy-900 rounded-md border border-slate-600 hover:border-yellow-500/50">
                <select
                  value={mode}
                  onChange={(e) => setMode(e.target.value as SearchMode)}
                  className="w-full h-full p-6 bg-transparent text-slate-100 font-cinzel text-sm font-bold tracking-wider outline-none appearance-none cursor-pointer hover:text-yellow-400 transition-colors"
                >
                  <option value={SearchMode.CASE_NAME}>CASE NAME / ISSUE</option>
                  <option value={SearchMode.CITATION}>CITATION</option>
                  <option value={SearchMode.TEXT_ANALYSIS}>RAW TEXT</option>
                </select>
                <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-yellow-500">
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7"></path></svg>
                </div>
              </div>

              {/* Input Field */}
              <div className="flex-grow relative bg-navy-900 rounded-md border border-slate-600 hover:border-yellow-500/50 focus-within:border-yellow-500 focus-within:ring-1 focus-within:ring-yellow-500 transition-all">
                {mode === SearchMode.TEXT_ANALYSIS ? (
                  <textarea 
                    value={query}
                    onChange={(e) => setQuery(e.target.value)}
                    placeholder="Paste full judgment text here..."
                    className="w-full p-6 bg-transparent text-white placeholder-slate-400 outline-none resize-none h-20 leading-relaxed font-serif text-lg"
                  />
                ) : (
                  <input
                    type="text"
                    value={query}
                    onChange={(e) => setQuery(e.target.value)}
                    onKeyDown={(e) => e.key === 'Enter' && onSearch()}
                    placeholder="Search case name, legal issue..."
                    className="w-full h-full p-6 bg-transparent text-white placeholder-slate-400 outline-none font-serif text-2xl"
                    autoComplete="off"
                  />
                )}

                {/* Autocomplete Dropdown */}
                {showSuggestions && (
                  <div className="absolute left-0 right-0 top-full mt-2 bg-navy-900 border border-slate-600 rounded-md shadow-2xl overflow-hidden z-[100]">
                    {suggestions.map((s, i) => (
                      <button 
                        key={i}
                        onClick={() => handleSuggestionClick(s)}
                        className="w-full text-left px-6 py-4 text-lg text-slate-200 hover:bg-slate-800 hover:text-yellow-400 font-serif border-b border-slate-700 last:border-0 transition-colors"
                      >
                        {s}
                      </button>
                    ))}
                  </div>
                )}
              </div>

              {/* Jurisdiction Select */}
              {mode !== SearchMode.TEXT_ANALYSIS && (
                 <div className="relative min-w-[180px] bg-navy-900 rounded-md border border-slate-600 hover:border-yellow-500/50">
                 <select
                   value={jurisdiction}
                   onChange={(e) => setJurisdiction(e.target.value as Jurisdiction)}
                   className="w-full h-full p-6 bg-transparent text-slate-200 text-xs font-cinzel font-bold tracking-widest outline-none appearance-none cursor-pointer hover:text-yellow-400 transition-colors uppercase"
                 >
                   {Object.values(Jurisdiction).map((j) => (
                     <option key={j} value={j}>{j}</option>
                   ))}
                 </select>
                 <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-slate-400">
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7"></path></svg>
                 </div>
               </div>
              )}

              {/* Search Button */}
              <button
                onClick={onSearch}
                disabled={!query.trim()}
                className="bg-yellow-600 hover:bg-yellow-500 disabled:bg-slate-800 disabled:text-slate-600 text-white font-cinzel font-bold text-lg py-4 px-12 transition-all duration-300 flex items-center justify-center gap-3 min-w-[180px] rounded-md border-t border-b border-yellow-400 shadow-[0_0_20px_rgba(234,179,8,0.3)] hover:shadow-[0_0_30px_rgba(234,179,8,0.6)]"
              >
                 <span className="tracking-widest drop-shadow-md">SEARCH</span>
              </button>
            </div>

            {/* Search History Chips - Brighter */}
            {history.length > 0 && (
              <div className="mt-6 flex items-center gap-3 overflow-x-auto pb-2 scrollbar-thin">
                <span className="text-xs text-slate-400 font-bold uppercase tracking-wider shrink-0 mr-2">RECENT:</span>
                {history.map((item, idx) => (
                   <button 
                     key={idx}
                     onClick={() => onHistorySelect(item)}
                     className="shrink-0 flex items-center gap-2 px-4 py-2 bg-navy-800 border border-slate-600 rounded-full hover:border-yellow-400 group transition-all"
                   >
                     <span className="text-xs text-slate-300 font-mono font-bold group-hover:text-yellow-300">{item.query}</span>
                     <span className="text-[9px] bg-black/50 px-1.5 py-0.5 rounded text-slate-400 border border-slate-700">{item.jurisdiction.slice(0,3).toUpperCase()}</span>
                   </button>
                ))}
              </div>
            )}

          </div>
        )}

      </div>
    </div>
  );
};

